package db

import (
	"context"
	"database/sql"
	"embed"
	"errors"
	"fmt"

	"github.com/golang-migrate/migrate/v4"
	"github.com/golang-migrate/migrate/v4/database/sqlite"
	"github.com/golang-migrate/migrate/v4/source/iofs"
)

//go:embed migrations/*.sql
var migrationsFS embed.FS

// runMigrations applies pending golang-migrate files (generated by
// ent/migrate/main.go) to db. Versioned migration state is tracked in the
// schema_migrations table that golang-migrate manages.
//
// Pre-flight: databases predating versioned migrations carry the ent schema
// without a schema_migrations row. Force-baseline the first version so the
// applier skips re-running DDL that would fail on already-existing tables.
func runMigrations(ctx context.Context, db *sql.DB) error {
	src, err := iofs.New(migrationsFS, "migrations")
	if err != nil {
		return fmt.Errorf("migration source: %w", err)
	}
	drv, err := sqlite.WithInstance(db, &sqlite.Config{})
	if err != nil {
		return fmt.Errorf("migration driver: %w", err)
	}
	m, err := migrate.NewWithInstance("iofs", src, "sqlite", drv)
	if err != nil {
		return fmt.Errorf("migrate init: %w", err)
	}

	_, _, vErr := m.Version()
	if errors.Is(vErr, migrate.ErrNilVersion) {
		var n int
		if err := db.QueryRowContext(ctx,
			`SELECT count(*) FROM sqlite_master WHERE type='table' AND name='users'`,
		).Scan(&n); err != nil {
			return fmt.Errorf("baseline probe: %w", err)
		}
		if n > 0 {
			first, err := src.First()
			if err != nil {
				return fmt.Errorf("baseline version lookup: %w", err)
			}
			if err := m.Force(int(first)); err != nil {
				return fmt.Errorf("baseline force: %w", err)
			}
		}
	} else if vErr != nil {
		return fmt.Errorf("migrate version: %w", vErr)
	}

	if err := m.Up(); err != nil && !errors.Is(err, migrate.ErrNoChange) {
		return fmt.Errorf("migrate up: %w", err)
	}
	return nil
}
